import json, os, re, runpy, sys, time
SCRIPT = os.path.join('copilot', 'scripts', 'runtime_launcher.py')
SKIP_DIRS = {'AppData', '.git', 'node_modules', '.venv', '__pycache__'}
PRODUCTS = ('Code', 'Code - Insiders')

def is_root(path):
    return os.path.isfile(os.path.join(path, 'plugin.json')) and os.path.isfile(os.path.join(path, SCRIPT))

def ascend_find(start):
    current = os.path.abspath(start)
    for _ in range(20):
        if is_root(current):
            return current
        parent = os.path.dirname(current)
        if parent == current:
            break
        current = parent
    return None

def walk_find(base, deadline):
    if not base or not os.path.isdir(base):
        return None
    base = os.path.abspath(base)
    base_depth = base.rstrip(os.sep).count(os.sep)
    seen = 0
    for current, dirs, _files in os.walk(base):
        seen += 1
        if seen > 12000 or time.monotonic() > deadline:
            return None
        depth = current.rstrip(os.sep).count(os.sep) - base_depth
        dirs[:] = [name for name in dirs if name not in SKIP_DIRS]
        if depth >= 6:
            dirs[:] = []
        if is_root(current):
            return current
    return None

def strip_jsonc_comments(text):
    result = []
    index = 0
    in_string = False
    escaping = False
    while index < len(text):
        char = text[index]
        next_char = text[index + 1] if index + 1 < len(text) else ''
        if in_string:
            result.append(char)
            if escaping:
                escaping = False
            elif char == '\\':
                escaping = True
            elif char == '"':
                in_string = False
            index += 1
            continue
        if char == '"':
            in_string = True
            result.append(char)
            index += 1
            continue
        if char == '/' and next_char == '/':
            index += 2
            while index < len(text) and text[index] not in '\r\n':
                index += 1
            continue
        if char == '/' and next_char == '*':
            index += 2
            while index + 1 < len(text) and not (text[index] == '*' and text[index + 1] == '/'):
                index += 1
            index += 2
            continue
        result.append(char)
        index += 1
    return ''.join(result)

def load_jsonc(path):
    try:
        with open(path, 'r', encoding='utf-8') as handle:
            text = handle.read()
    except OSError:
        return None
    text = strip_jsonc_comments(text)
    text = re.sub(r',(\s*[}\]])', r'\1', text)
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        return None

def settings_paths():
    candidates = []
    appdata = os.environ.get('APPDATA')
    home = os.path.expanduser('~')
    if appdata:
        for product in PRODUCTS:
            candidates.append(os.path.join(appdata, product, 'User', 'settings.json'))
    for product in PRODUCTS:
        candidates.append(os.path.join(home, 'Library', 'Application Support', product, 'User', 'settings.json'))
        candidates.append(os.path.join(home, '.config', product, 'User', 'settings.json'))
    return tuple(dict.fromkeys(os.path.abspath(path) for path in candidates))

def plugin_location_bases():
    bases = []
    for settings_path in settings_paths():
        settings = load_jsonc(settings_path)
        if not isinstance(settings, dict):
            continue
        locations = settings.get('chat.pluginLocations')
        if isinstance(locations, dict):
            for path, enabled in locations.items():
                if enabled is not False and isinstance(path, str) and path.strip():
                    bases.append(path)
        elif isinstance(locations, list):
            for entry in locations:
                if isinstance(entry, str) and entry.strip():
                    bases.append(entry)
        elif isinstance(locations, str) and locations.strip():
            bases.append(locations)
    return tuple(dict.fromkeys(os.path.abspath(os.path.expanduser(path)) for path in bases))

def agent_plugin_bases():
    candidates = []
    appdata = os.environ.get('APPDATA')
    home = os.path.expanduser('~')
    if appdata:
        for product in PRODUCTS:
            candidates.append(os.path.join(appdata, product, 'User', 'globalStorage', 'github.copilot-chat', 'agentPlugins'))
    for product in PRODUCTS:
        candidates.append(os.path.join(home, 'Library', 'Application Support', product, 'User', 'globalStorage', 'github.copilot-chat', 'agentPlugins'))
        candidates.append(os.path.join(home, '.config', product, 'User', 'globalStorage', 'github.copilot-chat', 'agentPlugins'))
    return tuple(dict.fromkeys(os.path.abspath(path) for path in candidates))

root = ascend_find(os.getcwd())
if root is None:
    deadline = time.monotonic() + 12.0
    for bases in (plugin_location_bases(), agent_plugin_bases()):
        for base in bases:
            root = walk_find(base, deadline)
            if root is not None:
                break
        if root is not None:
            break
if root is None:
    raise RuntimeError(f'Unable to resolve runtime launcher from cwd: {os.getcwd()}')
script = os.path.join(root, SCRIPT)
sys.argv = [script, 'memory']
runpy.run_path(script, run_name='__main__')

